const dayOfWeekName = $input.first().json["Day of week"];

const diasMap = {
  'Sunday': 0, 'Monday': 1, 'Tuesday': 2,
  'Wednesday': 3, 'Thursday': 4, 'Friday': 5, 'Saturday': 6
};

const dayOfWeek = diasMap[dayOfWeekName];
const esHabil = dayOfWeek >= 1 && dayOfWeek <= 5;
const diasEspanol = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];

return {
  esHabil,
  diaSemana: dayOfWeek,
  nombreDia: diasEspanol[dayOfWeek],
  hora: $input.first().json["Hour"]
};

const datos = $input.all().map(item => item.json);

const blue = datos.find(d => d.casa === 'blue');
const oficial = datos.find(d => d.casa === 'oficial');
const mep = datos.find(d => d.casa === 'bolsa');

const hora = $('¿Es día hábil?').first().json.hora;
const momento = Number(hora) < 12 ? '🌅 Apertura' : '🌆 Cierre';

const hoy = new Date().toLocaleDateString('es-AR', { day: '2-digit', month: '2-digit', year: 'numeric' });

const tcTexto = `💱 *TC Actualizado*\n\n📅 ${hoy} - ${momento}\n💵 Blue: $${blue?.venta || '-'}\n💵 Oficial: $${oficial?.venta || '-'}\n💵 MEP: $${mep?.venta || '-'}`;

return {
  dolar_blue: blue?.venta || null,
  dolar_oficial: oficial?.venta || null,
  dolar_mep: mep?.venta || null,
  tcTexto,
  momento
};

const transcripcion = $input.first().json.text;
const body = $('Webhook YCloud').first().json.body;

let from, customerName;

if (body.data?.key?.remoteJid) {
  // Evolution API
  from = body.data.key.remoteJid.replace('@s.whatsapp.net', '');
  customerName = body.data.pushName || '';
} else {
  // YCloud
  from = body.whatsappInboundMessage.from;
  customerName = body.whatsappInboundMessage.customerProfile?.name || '';
}

return {
  message: { text: transcripcion, from, customerName },
  esAudio: true
};

const body = $input.first().json.body;

let text, from, customerName;

if (body.data?.key?.remoteJid) {
  // Evolution API
  text = body.data.message?.conversation 
      || body.data.message?.extendedTextMessage?.text 
      || '';
  from = body.data.key.remoteJid.replace('@s.whatsapp.net', '');
  customerName = body.data.pushName || '';
} else {
  // YCloud
  text = body.whatsappInboundMessage?.text?.body || '';
  from = body.whatsappInboundMessage?.from || '';
  customerName = body.whatsappInboundMessage?.customerProfile?.name || '';
}

return {
  message: { text, from, customerName },
  esAudio: false
};

const body = $input.first().json.body;

// Evolution API: trae base64 directo
if (body.data?.message?.base64) {
  const base64 = body.data.message.base64;
  const buffer = Buffer.from(base64, 'base64');
  const binaryData = await this.helpers.prepareBinaryData(buffer, 'audio.ogg', 'audio/ogg');
  return [{ json: {}, binary: { data: binaryData } }];
}

// YCloud: hay que descargar desde URL
if (body.whatsappInboundMessage?.audio?.link) {
  const url = body.whatsappInboundMessage.audio.link;
  const response = await this.helpers.request({ method: 'GET', url, encoding: null });
  const binaryData = await this.helpers.prepareBinaryData(response, 'audio.ogg', 'audio/ogg');
  return [{ json: {}, binary: { data: binaryData } }];
}

throw new Error('No se encontró audio en el payload');
